mapper.sql:
SELECT ID, TALLY_ID, HQ_DATA_ID, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME FROM T_HQ_TALLY
and ID = #{id}
and TALLY_ID = #{tallyId}
and HQ_DATA_ID = #{hqDataId}

mapper.insert:
INSERT INTO T_HQ_TALLY( ID, TALLY_ID, HQ_DATA_ID, CREATE_BY, CREATE_BY_NAME, CREATE_TIME) (
SELECT #{item.id}, #{item.tallyId, jdbcType=VARCHAR}, #{item.hqDataId, jdbcType=VARCHAR}, #{item.loginUserId, jdbcType=BIGINT}, #{item.loginUserName, jdbcType=VARCHAR}, #{item.now} from dual
)
